import { Effect, Exit } from "effect";

class BoomError {
  readonly _tag = "BoomError" as const;
  constructor(readonly msg: string) {}
}

const flaky = (ok: boolean) =>
  ok ? Effect.succeed("ok") : Effect.fail(new BoomError("bang"));

async function run(ok: boolean): Promise<string> {
  const exit = await Effect.runPromiseExit(flaky(ok));
  return Exit.match(exit, {
    onSuccess: (value) => `resolved=${value}`,
    onFailure: (cause) => `caused=${cause._tag}`,
  });
}

void run(true);
void run(false);
