const worker = Effect.gen(function* () {
  yield* Effect.sleep("20 millis");
  return "daemon-done" as const;
});

const program = Effect.gen(function* () {
  const fiber = yield* Effect.forkDaemon(worker);
  yield* Effect.sleep("10 millis");
