Wrap the region with `Effect.uninterruptible` so a `Fiber.interrupt` from the outside is deferred until the region finishes. Use sparingly — only around finalizers and atomic commit points.

```typescript
import { Effect } from "effect";

const commit = Effect.gen(function* () {
  // simulate atomic DB write
  yield* Effect.sleep("10 millis");
  return "committed" as const;
});

const safeCommit = Effect.uninterruptible(commit);

Effect.runPromise(safeCommit).then((r) => {
  console.log(r);
});
```

`Effect.uninterruptibleMask` gives you a region that is uninterruptible by default but exposes a `restore` function so you can re-open a window that is interruptible again. This is useful when you need a mostly-atomic block with one cancellable wait inside.

```typescript
import { Effect } from "effect";

const guarded = Effect.uninterruptibleMask((restore) =>
  Effect.gen(function* () {
    // atomic prep phase
    yield* Effect.sleep("5 millis");
    // interruptible wait
    yield* restore(Effect.sleep("50 millis"));
    // atomic commit phase
    yield* Effect.sleep("5 millis");
    return "done" as const;
  }),
);

Effect.runPromise(guarded).then(console.log);
```

Release handlers should be uninterruptible so the lock is always freed.

```typescript
import { Effect } from "effect";

declare const acquire: Effect.Effect<{ readonly handle: number }>;
declare const release: (r: { readonly handle: number }) => Effect.Effect<void>;

export const withLock = <A, E>(eff: Effect.Effect<A, E>) =>
  Effect.acquireUseRelease(
    acquire,
    () => eff,
    (r) => Effect.uninterruptible(release(r)),
  );
```

```typescript
import { Effect, Fiber } from "effect";

const longWait = Effect.sleep("500 millis");

const guarded = Effect.uninterruptible(
  Effect.gen(function* () {
    // forced cancellable wait inside an otherwise atomic region
    yield* Effect.interruptible(longWait);
    return "past-wait" as const;
  }),
);

const program = Effect.gen(function* () {
  const fiber = yield* Effect.fork(guarded);
  yield* Effect.sleep("10 millis");
  yield* Fiber.interrupt(fiber);
  return "parent-done";
});

Effect.runPromise(program).then(console.log);
```

```typescript
import { pipe } from "fp-ts/function";
import * as T from "fp-ts/These";
import * as E from "fp-ts/Either";

type UserError = { readonly _tag: "TooShort" } | { readonly _tag: "Truncated" };

const validate = (raw: string): T.These<readonly UserError[], string> => {
  if (raw.length < 3) {
    return T.left([{ _tag: "TooShort" }]);
  }
  if (raw.length > 20) {
    return T.both([{ _tag: "Truncated" }], raw.slice(0, 20));
  }
  return T.right(raw);
};

const summarise = (v: T.These<readonly UserError[], string>): string =>
  pipe(
    v,
    T.fold(
      (errs) => `fail:${errs.map((e) => e._tag).join(",")}`,
      (ok) => `ok:${ok}`,
      (errs, ok) => `warn:${errs.map((e) => e._tag).join(",")}|${ok}`,
    ),
  );

console.log(summarise(validate("ab")));
console.log(summarise(validate("bob")));
console.log(summarise(validate("x".repeat(30))));
void E.right; // keep import stable for tsc
```

Use `T.fold` (or `T.match`) to project both the `Left` and the `Both` case into the `Either`'s error channel; the `Right` case becomes `E.right`.

```typescript
import { pipe } from "fp-ts/function";
import * as T from "fp-ts/These";
import * as E from "fp-ts/Either";

const toEither = <Err, A>(
  t: T.These<readonly Err[], A>,
): E.Either<readonly Err[], A> =>
  pipe(
    t,
    T.fold(
      (errs) => E.left(errs),
      (a) => E.right(a),
      (errs, _a) => E.left(errs),
    ),
  );

const example = toEither(T.both(["warn"], 42));
console.log(example);
```

`Either<E, A>` holds either an error or a value — never both. `These<E, A>` adds a third case `Both<E, A>` that carries warnings alongside a usable result, so you don't have to drop the value just because there were non-fatal issues.

```typescript
import { pipe } from "fp-ts/function";
import * as T from "fp-ts/These";

type Warn = "LEADING_SPACE" | "TRAILING_SPACE";

const cleanName = (raw: string): T.These<readonly Warn[], string> => {
  const warns: Warn[] = [];
  let out = raw;
  if (out.startsWith(" ")) warns.push("LEADING_SPACE");
  if (out.endsWith(" ")) warns.push("TRAILING_SPACE");
  out = out.trim();
  if (out.length === 0) return T.left(["LEADING_SPACE"]);
  return warns.length === 0 ? T.right(out) : T.both(warns, out);
};

const render = (x: T.These<readonly Warn[], string>) =>
  pipe(x, T.fold((e) => `err:${e.join("|")}`, (a) => `ok:${a}`, (e, a) => `both:${e.join("|")}:${a}`));

console.log(render(cleanName("  alice ")));
console.log(render(cleanName("bob")));
console.log(render(cleanName("   ")));
```

```typescript
import { pipe } from "fp-ts/function";
import * as T from "fp-ts/These";

interface Draft { readonly name: string; readonly age: number }
type Warn = "EMPTY_NAME" | "NEGATIVE_AGE";

const checkName = (n: string): T.These<readonly Warn[], string> =>
  n.length === 0 ? T.left(["EMPTY_NAME"]) : T.right(n);

const checkAge = (a: number): T.These<readonly Warn[], number> =>
  a < 0 ? T.both(["NEGATIVE_AGE"], 0) : T.right(a);

const merge = (d: Draft): T.These<readonly Warn[], Draft> => {
  const n = checkName(d.name);
  const a = checkAge(d.age);
  return pipe(
    n,
    T.fold(
      (e1) =>
        pipe(
          a,
          T.fold(
            (e2) => T.left([...e1, ...e2]),
            (_ok) => T.left(e1),
            (e2) => T.left([...e1, ...e2]),
          ),
        ),
      (name) =>
        pipe(
          a,
          T.fold(
            (e2) => T.left(e2),
            (age) => T.right({ name, age }),
            (e2, age) => T.both(e2, { name, age }),
          ),
        ),
      (e1, name) =>
        pipe(
          a,
          T.fold(
            (e2) => T.left([...e1, ...e2]),
            (age) => T.both(e1, { name, age }),
            (e2, age) => T.both([...e1, ...e2], { name, age }),
          ),
        ),
    ),
  );
};

console.log(merge({ name: "alice", age: -3 }));
```

