```typescript
import { Effect, Exit } from "effect";

type Result<A, E> =
  | { readonly _tag: "Ok"; readonly value: A }
  | { readonly _tag: "Err"; readonly error: E }
  | { readonly _tag: "Interrupted" };

export const settle = <A, E>(eff: Effect.Effect<A, E>): Effect.Effect<Result<A, E>> =>
  Effect.gen(function* () {
    const exit = yield* Effect.exit(eff);
    return Exit.match<A, E, Result<A, E>>(exit, {
      onSuccess: (value) => ({ _tag: "Ok", value }),
      onFailure: (cause) => {
        const maybeFail = cause._tag === "Fail" ? cause.error : undefined;
        if (maybeFail !== undefined) {
          return { _tag: "Err", error: maybeFail };
        }
        return { _tag: "Interrupted" };
      },
    });
  });
```

```typescript
import { Effect, Exit, Cause } from "effect";

class FetchError {
  readonly _tag = "FetchError" as const;
}

declare const fetchOrder: (id: string) => Effect.Effect<{ readonly id: string }, FetchError>;

const retryTypedOnly = <A, E>(
  eff: Effect.Effect<A, E>,
  maxAttempts: number,
): Effect.Effect<A, E> =>
  Effect.gen(function* () {
    let attempt = 0;
    while (true) {
      const exit = yield* Effect.exit(eff);
      if (Exit.isSuccess(exit)) return exit.value;
      if (Cause.isInterruptedOnly(exit.cause) || attempt >= maxAttempts) {
        return yield* Effect.failCause(exit.cause);
      }
      attempt += 1;
    }
  });

export const robust = (id: string) => retryTypedOnly(fetchOrder(id), 3);
```

