import { pipe } from "fp-ts/function";
import * as RA from "fp-ts/ReadonlyArray";
import * as O from "fp-ts/Option";

const evenOnly = (n: number): O.Option<number> =>
  n % 2 === 0 ? O.some(n) : O.none;

const sumDoubledEvens = (xs: ReadonlyArray<number>): number =>
  pipe(
    xs,
    RA.filterMap(evenOnly),
    RA.map((n) => n * 2),
    RA.reduce(0, (acc, n) => acc + n),
  );

console.log(sumDoubledEvens([1, 2, 3, 4, 5, 6]));
```

`A.traverse(E.Applicative)` turns `Array<A>` plus `A => Either<E, B>` into `Either<E, Array<B>>`, stopping at the first `Left`.

```typescript
import { pipe } from "fp-ts/function";
import * as A from "fp-ts/Array";
import * as E from "fp-ts/Either";

const parse = (s: string): E.Either<string, number> => {
  const n = Number(s);
  return Number.isNaN(n) ? E.left(`bad:${s}`) : E.right(n);
};

const result = pipe(["1", "2", "3"], A.traverse(E.Applicative)(parse));
console.log(result); // right([1, 2, 3])

const bad = pipe(["1", "x"], A.traverse(E.Applicative)(parse));
console.log(bad); // left('bad:x')
```

`A.map` + `A.filter` walks the list twice and needs you to pick a sentinel value for the discard case. `A.filterMap` walks once and uses `Option` as the discard marker: `O.some(b)` keeps the transformed element, `O.none` drops it.

```typescript
import { pipe } from "fp-ts/function";
import * as A from "fp-ts/Array";
import * as O from "fp-ts/Option";

const parseIntOpt = (s: string): O.Option<number> => {
  const n = Number(s);
  return Number.isInteger(n) ? O.some(n) : O.none;
};

const ints = pipe(["1", "x", "2.5", "3"], A.filterMap(parseIntOpt));
console.log(ints); // [1, 3]
```

