```typescript
import { Effect } from "effect";

const expensive = Effect.gen(function* () {
  yield* Effect.sleep("20 millis");
  return 42;
});

const program = Effect.gen(function* () {
  const cached = yield* Effect.cached(expensive);
  const a = yield* cached;
  const b = yield* cached; // no extra sleep — returns memoized value
  return a + b;
});

Effect.runPromise(program).then((n) => {
  console.log(n); // 84
});
```

`Effect.cached(inner)` returns an `Effect<Effect<A, E, R>, never, R>`. Yielding the outer effect once produces an inner effect whose first evaluation runs `inner` and whose subsequent evaluations reuse the same `Exit`.

```typescript
import { Effect } from "effect";

const fetchConfig = Effect.sync(() => ({ flag: true }));

const program = Effect.gen(function* () {
  const cached = yield* Effect.cached(fetchConfig);
  const c1 = yield* cached;
  const c2 = yield* cached;
  return c1 === c2; // true — same referential result
});

Effect.runPromise(program).then(console.log);
```

`Effect.cached` caches forever (for the lifetime of the outer effect). `Effect.cachedWithTTL(inner, duration)` caches the result but invalidates it after the TTL, so the next yield re-runs `inner`. Use it for config values that occasionally change but should not be fetched on every call.

```typescript
import { Effect } from "effect";

const fetchRate = Effect.sync(() => Math.random());

const program = Effect.gen(function* () {
  const cached = yield* Effect.cachedWithTTL(fetchRate, "100 millis");
  const a = yield* cached;
  yield* Effect.sleep("10 millis");
  const b = yield* cached; // same value — TTL not expired
  yield* Effect.sleep("120 millis");
  const c = yield* cached; // refreshed — TTL elapsed
  return { a, b, c };
});

Effect.runPromise(program).then((r) => {
  console.log(r.a === r.b, r.b !== r.c);
});
```

Hoist `Effect.cached` to a single acquisition point and share the resulting inner effect among dependents.

```typescript
import { Effect } from "effect";

interface Config { readonly flag: boolean }

declare const fetchConfig: Effect.Effect<Config>;

export const program = Effect.gen(function* () {
  const cachedCfg = yield* Effect.cached(fetchConfig);
  const [flagA, flagB] = yield* Effect.all(
    [
      Effect.map(cachedCfg, (c) => c.flag),
      Effect.map(cachedCfg, (c) => c.flag),
    ],
    { concurrency: "unbounded" },
  );
  return flagA && flagB;
});
```

```typescript
import { Effect } from "effect";

export const memoize = <A, E, R>(inner: Effect.Effect<A, E, R>) =>
  Effect.cached(inner);

const loadUser = (id: string) =>
  Effect.gen(function* () {
    yield* Effect.sleep("5 millis");
    return { id, name: `user-${id}` } as const;
  });

const request = Effect.gen(function* () {
  const cached = yield* memoize(loadUser("42"));
  const a = yield* cached;
  const b = yield* cached;
  return a === b;
});

Effect.runPromise(request).then(console.log);
