Return both the cached inner effect and a fresh evaluation of the original so callers can choose.

```typescript
import { Effect } from "effect";

interface CachedSource<A, E, R> {
  readonly get: Effect.Effect<A, E, R>;
  readonly forceRefresh: Effect.Effect<A, E, R>;
}

export const makeCached = <A, E, R>(
  source: Effect.Effect<A, E, R>,
): Effect.Effect<CachedSource<A, E, R>, never, R> =>
  Effect.gen(function* () {
    const cached = yield* Effect.cached(source);
    return { get: cached, forceRefresh: source } as const;
  });

